import React, { useState } from 'react';
import { useNavigate } from 'react-router-dom';
import DatePicker from 'react-datepicker';
import Select from 'react-select';
import { SearchCriteria, Child } from '../../types';
import { CURRENCIES, COUNTRIES } from '../../constants';
import { addDays } from '../../utils';
import 'react-datepicker/dist/react-datepicker.css';

const SearchForm: React.FC = () => {
  const navigate = useNavigate();
  const [formData, setFormData] = useState<Partial<SearchCriteria>>({
    location: '',
    checkIn: new Date(),
    checkOut: addDays(new Date(), 1),
    currency: 'TRY',
    nationality: 'TR',
    adults: 2,
    children: [],
  });

  const [errors, setErrors] = useState<string[]>([]);

  // Para birimi seçenekleri
  const currencyOptions = CURRENCIES.map(currency => ({
    value: currency.value,
    label: currency.label,
  }));

  // Ülke seçenekleri
  const countryOptions = COUNTRIES.map(country => ({
    value: country.value,
    label: country.label,
  }));

  // Form güncelleme
  const handleInputChange = (field: keyof SearchCriteria, value: any) => {
    setFormData(prev => ({ ...prev, [field]: value }));
  };

  // Çocuk ekleme/çıkarma
  const handleChildChange = (index: number, age: number) => {
    const newChildren = [...(formData.children || [])];
    newChildren[index] = { age };
    setFormData(prev => ({ ...prev, children: newChildren }));
  };

  const addChild = () => {
    const newChildren = [...(formData.children || []), { age: 5 }];
    setFormData(prev => ({ ...prev, children: newChildren }));
  };

  const removeChild = (index: number) => {
    const newChildren = (formData.children || []).filter((_, i) => i !== index);
    setFormData(prev => ({ ...prev, children: newChildren }));
  };

  // Form gönderme
  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    
    // Validasyon
    const validationErrors: string[] = [];
    
    if (!formData.location?.trim()) {
      validationErrors.push('Lokasyon seçimi zorunludur');
    }
    
    if (!formData.checkIn || !formData.checkOut) {
      validationErrors.push('Tarih seçimi zorunludur');
    } else if (formData.checkIn >= formData.checkOut) {
      validationErrors.push('Çıkış tarihi giriş tarihinden sonra olmalıdır');
    }

    if (validationErrors.length > 0) {
      setErrors(validationErrors);
      return;
    }

    setErrors([]);
    
    // URL parametrelerini oluştur ve yönlendir
    const params = new URLSearchParams({
      location: formData.location!,
      checkIn: formData.checkIn!.toISOString(),
      checkOut: formData.checkOut!.toISOString(),
      currency: formData.currency!,
      nationality: formData.nationality!,
      adults: formData.adults!.toString(),
      children: JSON.stringify(formData.children),
    });

    navigate(`/search?${params.toString()}`);
  };

  return (
    <div className="card p-6 shadow-medium">
      <form onSubmit={handleSubmit} className="space-y-6">
        {/* Hata mesajları */}
        {errors.length > 0 && (
          <div className="bg-red-50 border border-red-200 rounded-lg p-4">
            <ul className="text-red-600 text-sm space-y-1">
              {errors.map((error, index) => (
                <li key={index}>• {error}</li>
              ))}
            </ul>
          </div>
        )}

        {/* Lokasyon */}
        <div>
          <label className="block text-sm font-medium text-gray-700 mb-2">
            Nereye gitmek istiyorsunuz?
          </label>
          <input
            type="text"
            value={formData.location}
            onChange={(e) => handleInputChange('location', e.target.value)}
            placeholder="Şehir, otel veya destinasyon"
            className="input-field"
          />
        </div>

        {/* Tarih seçimi */}
        <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
          <div>
            <label className="block text-sm font-medium text-gray-700 mb-2">
              Giriş Tarihi
            </label>
            <DatePicker
              selected={formData.checkIn}
              onChange={(date) => handleInputChange('checkIn', date)}
              minDate={new Date()}
              className="input-field"
              dateFormat="dd/MM/yyyy"
              placeholderText="Giriş tarihi seçin"
            />
          </div>
          <div>
            <label className="block text-sm font-medium text-gray-700 mb-2">
              Çıkış Tarihi
            </label>
            <DatePicker
              selected={formData.checkOut}
              onChange={(date) => handleInputChange('checkOut', date)}
              minDate={formData.checkIn ? addDays(formData.checkIn, 1) : new Date()}
              className="input-field"
              dateFormat="dd/MM/yyyy"
              placeholderText="Çıkış tarihi seçin"
            />
          </div>
        </div>

        {/* Misafir bilgileri */}
        <div className="space-y-4">
          <label className="block text-sm font-medium text-gray-700">
            Misafirler
          </label>
          
          {/* Yetişkin sayısı */}
          <div className="flex items-center justify-between">
            <span className="text-gray-600">Yetişkin</span>
            <div className="flex items-center space-x-3">
              <button
                type="button"
                onClick={() => handleInputChange('adults', Math.max(1, (formData.adults || 2) - 1))}
                className="w-8 h-8 rounded-full border border-gray-300 flex items-center justify-center hover:bg-gray-50"
              >
                -
              </button>
              <span className="w-8 text-center">{formData.adults}</span>
              <button
                type="button"
                onClick={() => handleInputChange('adults', (formData.adults || 2) + 1)}
                className="w-8 h-8 rounded-full border border-gray-300 flex items-center justify-center hover:bg-gray-50"
              >
                +
              </button>
            </div>
          </div>

          {/* Çocuk sayısı */}
          <div className="flex items-center justify-between">
            <span className="text-gray-600">Çocuk</span>
            <div className="flex items-center space-x-3">
              <button
                type="button"
                onClick={() => {
                  if (formData.children && formData.children.length > 0) {
                    removeChild(formData.children.length - 1);
                  }
                }}
                className="w-8 h-8 rounded-full border border-gray-300 flex items-center justify-center hover:bg-gray-50"
              >
                -
              </button>
              <span className="w-8 text-center">{formData.children?.length || 0}</span>
              <button
                type="button"
                onClick={addChild}
                className="w-8 h-8 rounded-full border border-gray-300 flex items-center justify-center hover:bg-gray-50"
              >
                +
              </button>
            </div>
          </div>

          {/* Çocuk yaşları */}
          {formData.children && formData.children.length > 0 && (
            <div className="space-y-2">
              {formData.children.map((child, index) => (
                <div key={index} className="flex items-center justify-between">
                  <span className="text-gray-600">Çocuk {index + 1} yaşı</span>
                  <select
                    value={child.age}
                    onChange={(e) => handleChildChange(index, parseInt(e.target.value))}
                    className="px-3 py-1 border border-gray-300 rounded-md"
                  >
                    {Array.from({ length: 18 }, (_, i) => (
                      <option key={i} value={i}>
                        {i} yaş
                      </option>
                    ))}
                  </select>
                </div>
              ))}
            </div>
          )}
        </div>

        {/* Para birimi ve ülke */}
        <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
          <div>
            <label className="block text-sm font-medium text-gray-700 mb-2">
              Para Birimi
            </label>
            <Select
              value={currencyOptions.find(option => option.value === formData.currency)}
              onChange={(option) => handleInputChange('currency', option?.value)}
              options={currencyOptions}
              className="react-select-container"
              classNamePrefix="react-select"
            />
          </div>
          <div>
            <label className="block text-sm font-medium text-gray-700 mb-2">
              Uyruk
            </label>
            <Select
              value={countryOptions.find(option => option.value === formData.nationality)}
              onChange={(option) => handleInputChange('nationality', option?.value)}
              options={countryOptions}
              className="react-select-container"
              classNamePrefix="react-select"
            />
          </div>
        </div>

        {/* Arama butonu */}
        <button
          type="submit"
          className="w-full btn-primary py-3 text-lg font-semibold"
        >
          Otel Ara
        </button>
      </form>
    </div>
  );
};

export default SearchForm;
